def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 5:
            for a in range(5, 0, -1):
                for b in range(1, a + 2):
                    penalty = ((ratio - a) ** 4) / (a * b)
                    priority += penalty * np.cos(ratio * b)
            priority += np.exp(ratio - 5) * np.sin(ratio)
        elif 2 < ratio <= 5:
            for m in range(1, int(np.ceil(ratio)) + 2):
                for n in range(1, m + 1):
                    priority += ((ratio - m) * np.sin(ratio * m)) / (n + 1)
            priority += np.log(ratio) * 7 - np.tanh(ratio - 2)
        elif 1 <= ratio <= 2:
            s = 0
            for k in range(1, 10):
                s += ((ratio - 1) ** k) / (k * 2)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 4 + np.tanh(3 * (2 - ratio))
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 7):
                s += ((1 - ratio) ** n) / n ** 2
            if bin_cap < item:
                penalty = np.sqrt(item / (bin_cap + 1)) * 3
            else:
                penalty = np.cos(15 * ratio) * 2
            priority = s + penalty + np.exp(-1 / (ratio + 0.1))
        elif 0.2 <= ratio < 0.5:
            s = 0
            for n in range(1, 10):
                s += ((0.5 - ratio) ** n) / (n * 3)
            priority = s
            if (i + int(item)) % 3 == 0:
                priority *= np.log1p(bin_cap + 2)
            else:
                priority /= (np.sqrt(bin_cap + 1) + 1)
            for j in range(1, 4):
                priority += ((0.5 - ratio) ** j) * np.sin(j * item)
        else:
            s = 0
            for k in range(1, 8):
                s += ((0.2 - ratio) ** k) / (k * 4)
            priority = s + 1 / (bin_cap + 2)
            if int(item) % 3 == 0:
                priority *= 2
            else:
                priority /= 2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3
            else:
                priority -= np.exp(-ratio) * 2
            for m in range(1, 5):
                priority += ((0.2 - ratio) ** m) / (m * 5) * np.cos(item * m)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 4
        elif bin_cap > item * 3:
            priority -= np.exp(-2 * ratio) * 3
        if i % 2 == 0:
            priority += np.sin(ratio * i) * 0.5
        else:
            priority -= np.cos(ratio * i) * 0.5
        priorities[i] = priority
    return priorities
